#!/usr/bin/env python3
import base64, os, sys
if not os.path.isfile("App.js"): sys.exit("Run from BatKnock root")

os.makedirs("data", exist_ok=True)
with open("data/seasonData.js", "wb") as f: f.write(base64.b64decode(""))
print("OK data/seasonData.js")

with open("ThemeContext.js", "wb") as f: f.write(base64.b64decode(""))
print("OK ThemeContext.js")

os.makedirs("screens", exist_ok=True)
with open("screens/HomeScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/HomeScreen.js")

os.makedirs("screens", exist_ok=True)
with open("screens/BatListScreen.js", "wb") as f: f.write(base64.b64decode(""))
print("OK screens/BatListScreen.js")

print()
print("Run: npx expo start --clear --lan")
print()
print("Changes:")
print("  - Two-tone text: white+blue (dark), navy+blue (light)")
print("  - Light theme accent blue darkened for visibility")
print("  - HomeScreen: content moves lower, header tightened")
print("  - Settings panel expanded by default")
print("  - Default theme: Auto, default font: medium-large")
print("  - BatList cards: larger text throughout")
print("  - India: corrected to year-round cricket")
